#!/usr/bin/env bash
# update.sh — one-shot "ship it" script for esp32-boat.
#
# What it does, in order:
#   1. Rebuilds the sim firmware and refreshes binaries/*.bin so the
#      committed pre-built images always match the source.
#   2. Prepends a dated entry to CHANGELOG.md with the commit message.
#   3. Shows you what changed (git status + short diff stat).
#   4. Stages every change under tracked folders (src/, scripts/, binaries/,
#      hardware/, docs/, README.md, .gitignore, platformio.ini, include/,
#      CHANGELOG.md).
#   5. Commits with the message you pass in (or the DEFAULT_MSG below,
#      which Claude updates each time the repo changes).
#   6. Pushes to origin on the current branch.
#
# Usage:
#   ./scripts/update.sh                          # use DEFAULT_MSG below
#   ./scripts/update.sh "custom commit message"  # override
#   ./scripts/update.sh -n                       # skip firmware rebuild
#   ./scripts/update.sh -n "docs-only tweak"     # skip build + custom msg
#
# Exit codes:
#   0 success    1 build failed    2 git failed    3 user aborted

# ============================================================================
# DEFAULT_MSG — the commit message for the current set of uncommitted
# changes. Claude updates this each time it modifies the repo, so you can
# just run `./scripts/update.sh` with no arguments and get a meaningful
# commit. Override by passing a message as the first positional argument.
# ============================================================================
DEFAULT_MSG="Display bring-up round 27: replace the 5-phase RGB solid-colour bar in src/Ui.cpp with a 16-phase walking-bit diagnostic. Each phase drives exactly ONE pixel bit HIGH across the whole 480×480 frame — fillColor(0x0001), fillColor(0x0002), fillColor(0x0004), ..., fillColor(0x8000) — and dwells 3 s, with paired before-and-after log lines naming the bit position, the panel channel (B0..B4 / G0..G5 / R0..R4), and the specific GPIO carrying that slot in data_gpio_nums[] (B0=GPIO5, B1=GPIO45, B2=GPIO48, B3=GPIO47, B4=GPIO21, G0=GPIO14, G1=GPIO13, G2=GPIO12, G3=GPIO11, G4=GPIO10, G5=GPIO9, R0=GPIO46, R1=GPIO3, R2=GPIO8, R3=GPIO18, R4=GPIO17). Why this is the right diagnostic now: round-26 photos IMG_1825-1829 (mostly-identical to round-25 IMG_1820-1824 — confirming the 0xC2 revert had no visible effect) told us the fault isn't inversion-mode or pixel-format but a bus-level problem. The smoking-gun frame was IMG_1828: we sent pixel 0xFFFF (all 16 data lines HIGH, which must render as WHITE if the bus is intact) and the panel rendered the SAME full-screen bright blue it had shown on IMG_1827 (0x001F, only low 5 bits HIGH). If bits 5-15 were reaching the panel, 0xFFFF would saturate all three channels and produce white. It doesn't. Which means the upper 11 data lines — the 11 GPIOs carrying G0..G5 and R0..R4 — are not arriving at the panel's source drivers, and only the 5 GPIOs carrying B0..B4 (GPIOs 5, 45, 48, 47, 21) are functional from the bus perspective. No amount of ST7701-register editing fixes that. Round 27's walking-bit test replaces coarse channel-at-a-time fills with bit-at-a-time fills so the user's photos directly map each of 16 GPIOs to 'lights up / stays dark'. Expected result and interpretation for round 27: (a) BITS 0..4 phases (B0..B4, GPIOs 5/45/48/47/21) should each show a dim blue tint on the panel's blue LED — confirming these 5 GPIOs reach their panel pads correctly; (b) BITS 5..15 phases (G0..G5, R0..R4, GPIOs 14/13/12/11/10/9/46/3/8/18/17) will each be photographed to see which, if any, produce panel output. Most likely outcome: all 11 of these phases stay black, confirming those GPIOs are the fault group. A narrower outcome — 1 or 2 of the 11 light up — would mean only a subset is bad, narrowing the hardware hunt further. Either way round 28 acts on real per-pin data instead of guessing registers. After the 16 bit-walk phases, an abbreviated 5-phase RGB sanity bar (2 s each) replays RED/GREEN/BLUE/WHITE/BLACK for direct comparison against IMG_1825-1829 so we can see that the pattern is reproducible on this boot. Total diagnostic boot duration: 48 s bit-walk + 10 s sanity bar ≈ 1 minute before LVGL takes over. No ST7701 panel-driver or init-table changes in this round — the fault isn't in the panel. Nothing in platformio.ini or display_pins.h changes yet; if a GPIO is implicated by the walking-bit photos, round 28 will make the pinout fix (likely: some of 9..14, 3, 8, 17, 18, 46 are wrong in display_pins.h and need to be replaced with the correct Waveshare ESP32-S3-Touch-LCD-2.1 schematic values — display_pins.h was populated from LovyanGFX community discussion #630 which may document a different panel revision than our physical board). Only file touched this round: src/Ui.cpp, inside the existing if(g_panel.begin) block. Every earlier round's fix stays intact: round-22 COLMOD=0x55, round-24 single-call fillColor(), round-26 0xC2={0x20,0x06}, round-20 PCLK/porch retuning, round-19 verbatim-espressif GIP port. Historical context preserved from round 26: REVERT round 25. Round 25 changed ST7701 register 0xC2 from espressif's {0x20, 0x06} to a Waveshare-factory {0x07, 0x0A} to chase the vertical-stripe symptom; photos IMG_1820-1824 showed the change caused a dramatic regression — the panel's outer ~2/3 went completely black with only a narrow centred band of data visible in the middle third, and the upper data bits (R0..R4 and most of G) stopped reaching the source drivers entirely. That made the round-25 output strictly worse than round-24. Rolling back to {0xC2, {0x20, 0x06}, 2, 0} restored the round-24 state. But round-26 photos IMG_1825-1829 came back visually identical to round-25 IMG_1820-1824, which in retrospect means the 'regression' I attributed to 0xC2 was never about 0xC2 at all — the upper-bits-dead symptom was already present throughout rounds 22-26, and I had been misreading the earlier rounds' photos as 'full-screen solid fills with stripe artifacts' when in fact the fills had already been restricted to the middle third. The round-26 revert therefore produced no visible change precisely because there was nothing to undo. This wasted round is what pushed round 27 toward a hard-data diagnostic instead of another register guess. Historical context preserved from round 25: switch ST7701 0xC2 from espressif's {0x20, 0x06} to Waveshare's factory-firmware {0x07, 0x0A} Round 25 changed ST7701 register 0xC2 from espressif's {0x20, 0x06} to a Waveshare-factory {0x07, 0x0A} to chase the vertical-stripe symptom; photos IMG_1820-1824 show the change caused a dramatic regression. IMG_1820 (RED phase 0xF800) and IMG_1821 (GREEN phase 0x07E0) both show the panel's outer ~2/3 completely black with only a narrow centred band of BLUE stripes in the middle third — RED and GREEN are not appearing at all. IMG_1822 (BLUE phase 0x001F) shows full-screen blue correctly but with a centred band of GREEN stripes through the middle. IMG_1823 (WHITE phase 0xFFFF) shows blue instead of white; IMG_1824 (LVGL Overview rendering) shows the UI in the wrong colours (green text on blue background). The colour-channel pattern across all five phases says the upper data bits stopped reaching the source drivers entirely — only the low-5-bit blue data on DB[4..0] is making it through — which is a side-effect {0x07, 0x0A} has on this specific panel module beyond the intended inversion-mode change. That value may be valid for some other Waveshare ST7701 variant but definitively is not right for the ESP32-S3-Touch-LCD-2.1 as strapped. Rolling back: {0xC2, {0x07, 0x0A}, 2, 0} reverts to {0xC2, {0x20, 0x06}, 2, 0}, which restores round 24's state where the panel at least drove full-screen solid fills with each colour appearing correctly across the whole surface, the residual issue being a 'middle column shows previous phase's colour' stripe artifact rather than entire-channel drop-out. Round 24's state is strictly closer to working than round 25's state. Long-form comment above the 0xC2 entry now records the round-25 regression and revert so nobody tries {0x07, 0x0A} again on this panel. Nothing else changes — 0x3A COLMOD=0x55 from round 22 stays in the init table, fillColor()'s single full-screen draw_bitmap from round 24 stays as-is, and the 5 s colour-bar diagnostic from round 23 in src/Ui.cpp is still driving the test. Next step (round 27) pivots to a completely different hypothesis for the middle-column stripe: reverse data_gpio_nums[] order. Some ESP-IDF 4.4.7 RGB-peripheral versions put bit 0 of the pixel on the LAST array slot instead of the first, and if our array is 'backwards' then upper pixel bits land on the lowest-indexed panel data pins and vice-versa, producing exactly the kind of column-position-dependent artifact we're seeing — half the columns get correct data because of how the DMA burst aligns, the other half get byte-swapped data. Cheap single-file test: reverse kInitCmds[]'s unrelated, change the 16 initRgbPanel() data_gpio_nums[i] assignments from [0..15] mapping B0..R4 to [0..15] mapping R4..B0. If the stripe disappears → pin order was it. If the stripe relocates or changes shape → we're in the pin-order family and fine-tune. If unchanged → pin order is fine and round 28 tries dropping PCLK to 6 MHz. Historical context preserved from round 25: switch ST7701 0xC2 from espressif's {0x20, 0x06} to Waveshare's factory-firmware {0x07, 0x0A} to kill the stable vertical-stripe pattern on solid-colour fills. Rounds 22–24 chased the persistent vertical-stripe / 'middle column shows previous phase's colour' symptom through three different theories — (a) COLMOD pixel-format mismatch fixed in round 22 by re-adding 0x3A=0x55, which did eliminate the round-21 diagonal drift and the white-phase inversion, confirming 16-bit RGB565 bit-alignment is now correct; (b) photo-timing confusion between fillColor call and panel steady state, fixed in round 23 by extending each colour-bar phase from 2 s to 5 s and adding a paired AFTER-fillColor log line so the user could photograph the panel's true steady state; (c) PSRAM-framebuffer cache/DMA burst-boundary coherency, attempted in round 24 by rewriting fillColor() to allocate one full-screen 480×480×2=460 800-byte PSRAM buffer, fill it once, and issue a single esp_lcd_panel_draw_bitmap() call for the whole panel instead of 480 per-row calls. Round 24's photos come back visually UNCHANGED from round 23 — same vertical stripes, same 'middle column shows previous phase' pattern, the only difference being photo angle. That invariance between multi-row and single-write is diagnostic: the stripes are NOT a cache/DMA race condition, because a single contiguous memcpy-to-framebuffer would have eliminated them if they were. The stripes are stable across both write strategies, which rules out anything in the CPU-to-PSRAM write path. What DOES cause stable vertical stripes on a uniform-colour fill is the panel's own per-frame polarity-inversion scheme mis-matching the TFT glass. The ST7701 supports column-inversion, 1-dot, 2-dot, and 4-dot inversion patterns via register 0xC2 bits [6:5]; each pattern needs the source-driver amplifiers to be voltage-balanced against the pattern it's asked to produce. A mismatch shows up exactly the way we're seeing it — steady vertical bands where every second column (or every second column-pair) drifts darker or lighter than its neighbour because the + and − polarity source drives aren't symmetric on this specific panel module. Espressif's reference BSP uses {0x20, 0x06} — 1-dot inversion with a 6-frame period — which is tuned for espressif's own reference panel module. Waveshare's own ESP32-S3-Touch-LCD-2.1 factory firmware uses {0x07, 0x0A} — column inversion (bits [6:5] = 00) with a different lower-byte timing trim — tuned for the specific glass Waveshare laminates onto this PCB. This is the single most suspect register we haven't touched, and it specifically targets the vertical-stripe symptom rather than anything upstream (init protocol, RGB timing, pin mapping) which we've now thoroughly exhausted. Single-line change in src/display/st7701_panel.cpp::kInitCmds[]: {0xC2, {0x20, 0x06}, 2, 0} becomes {0xC2, {0x07, 0x0A}, 2, 0}. Long-form comment above the entry records the round-25 narrative so the next developer cross-referencing espressif's reference doesn't flip it back. Everything else from rounds 22–24 stays intact: 0x3A COLMOD=0x55 still in the init table, fillColor() still does its single full-screen draw_bitmap, the colour-bar diagnostic in src/Ui.cpp still runs with 5 s dwell and paired settled-photograph-now log lines. Interpretation of round-25 photos: (a) if the stripes disappear and each phase shows a full-screen solid colour matching what fillColor sent → inversion was it, round 26 removes the colour-bar diagnostic and validates LVGL Overview page renders cleanly; (b) if stripes persist but their WIDTH or SPACING changes → we're still in the inversion-mode family and round 26 tries {0x31, 0x05} (2-dot inversion) or {0x37, 0x05} (4-dot); (c) if stripes are completely unchanged → inversion isn't it and the suspect shifts to the remaining big-hammer options: pclk_active_neg back to 1 (flipped 1→0 in round 16 but only ever tested through LVGL's centred content until round 21's colour bar, and the diagonal drift from rounds 15–20 may have masked a residual wrong-edge sample), data_gpio_nums reversed (to test whether IDF 4.4.7's RGB peripheral puts bit 0 on the array's LAST slot rather than the first), or dropping PCLK from 10 MHz to 6 MHz to rule out any remaining bandwidth pressure between the RGB peripheral and octal PSRAM. Historical context preserved from round 24: rewrite fillColor() from 480 per-row esp_lcd_panel_draw_bitmap() calls into one single full-screen call. The round-23 colour-bar photos (IMG_1815-1819) all showed the same pattern — outer columns display the new colour correctly, middle third always shows the previous phase's colour (RED phase showed blue middle, GREEN showed blue, BLUE showed green, WHITE showed darker-blue, BLACK showed greenish-dark). That pattern read as a textbook IDF-4.4.7 PSRAM-framebuffer coherency hole: the RGB peripheral reads PSRAM in fixed-size DMA bursts while the CPU writes rows through the cache, and with 480 small per-row writes the cache-to-DMA sync drops the middle of each line (the bursts that straddle the 160-column and 320-column boundaries). Fix attempted: allocate one full-screen 460 800-byte PSRAM buffer, fill it with the solid colour, and call esp_lcd_panel_draw_bitmap() exactly ONCE for the entire screen so IDF's internal memcpy-to-framebuffer runs as a single contiguous operation with cache/DMA sync at known-good boundaries. Memory budget: 460 KB temporary allocation freed immediately after draw, bringing peak usage to ~920 KB + LVGL's ~77 KB double-buffer = under 1.1 MB total, well inside our 8 MB PSRAM. Round 24's photos came back unchanged from round 23, which is how we arrived at round 25's inversion-register hypothesis. Historical context preserved from round 23: extend each colour-bar phase from 2 s to 5 s and add a paired AFTER-fillColor log line, so the user can photograph the panel's true steady state instead of frame-transition artifacts. Round 22 photos (IMG_1812/1813/1814) showed THREE distinct patterns — not the single repeating diagonal we saw in round 21 — plus a large solid-blue region with a sharp diagonal cutoff in IMG_1814. The per-colour variation confirms COLMOD=0x55 is taking effect: the panel is now interpreting our bits as 16-bit RGB565 rather than smearing them across 18-bit RGB666 sub-pixel boundaries, which was the round 21 symptom. But the remaining diagonal-stripe region plus the user's observation that 'the display changes about 1 second after the monitor log' indicates we were photographing mostly frame transitions, not steady-state. Root cause: the ESP32-S3 RGB peripheral in IDF 4.4.7 uses a SINGLE in-place PSRAM framebuffer with no double-buffering support; fillColor() writes 480 rows sequentially via esp_lcd_panel_draw_bitmap, and while those writes are in progress the peripheral's continuous scan catches up to the write pointer and displays a mix of old and new frame content. The sharp diagonal cutoff in IMG_1814 is literally the scan line where the panel's read pointer overtook our write pointer mid-frame. With only 2 s per colour phase, the photo window overlaps this tearing for a meaningful fraction of the time. Round 23 fixes the observability problem rather than the display problem. src/Ui.cpp::ui::begin() gets two changes inside the colour-bar block: (a) each phase delay extends from 2000 ms to 5000 ms (BLACK hold extended 1000 ms to 3000 ms), and (b) every phase now logs two lines — '<colour> starting' before fillColor returns, then '<colour> settled — photograph now' after. Total boot-time added: roughly 15 s on top of the existing ~9 s, so the colour-bar sequence runs for ~24 s before LVGL takes over — harmless for a one-off diagnostic boot. No panel driver changes. The 0x3A COLMOD=0x55 from round 22 stays in src/display/st7701_panel.cpp, the verbatim-espressif BK0/BK1 init and the Espressif-typical RGB timings from rounds 19/20 both stay intact. Interpretation of round-23 photos: (a) if each colour phase settles to a FULL-SCREEN SOLID colour matching what we sent → panel bring-up is DONE and round 24 removes the colour-bar diagnostic plus validates LVGL renders the Overview page cleanly. (b) if the diagonal stripe remnant survives the 4 s of steady state after each fillColor settles → the remaining artifact isn't a transition issue and needs a real fix; most likely candidates in decreasing order are pclk_active_neg back to 1 (we flipped 1→0 in round 16 but only tested through LVGL's centred content, which masked a diagonal), data_gpio_nums[] reversed (to test whether IDF 4.4.7's RGB peripheral puts bit 0 on the array's last slot instead of the first), or data_width=8 to rule out a 16-bit-specific routing bug in the peripheral. (c) if the colour the panel actually displays does not match what fillColor sent (e.g. RED fill shows BLUE steady-state) → RGB_PIN_R* / RGB_PIN_G* / RGB_PIN_B* sub-blocks in data_gpio_nums[] need to be shuffled; the specific 'fill→visible' mapping tells us which channels to swap. Historical context preserved from round 22: re-add the 0x3A COLMOD command with value 0x55 (16-bit RGB565 on the RGB interface). Round 21's colour-bar diagnostic produced the cleanest signal we've had since round 13. With the full-screen RED/GREEN/BLUE/WHITE/BLACK fill bypassing LVGL entirely, the photo showed DIAGONAL stripes running across the WHOLE 480x480 round panel on every solid-colour phase, with the stripe pattern INVERTING when the WHITE phase (0xFFFF — every DB pin HIGH) ran. That retroactively explains rounds 15–20: the 'narrow vertical band of stripes in the middle of the screen' those photos captured was LVGL's centre-aligned UI widgets sitting on top of the same full-panel diagonal stripe pattern, hidden everywhere else because LVGL's black screen background also rendered as one of the 'dark' colours in the stripe cycle, blending into the panel's miscoloured 'background' state. Geometry was never broken; the panel was accepting data for the whole screen all along. The diagonal-stripes-plus-invert-on-white fingerprint is a textbook pixel-format mismatch: the panel is latching 18 bits per pixel (its ST7701S-datasheet reset default for the RGB interface, 0x3A = 0x66 / RGB666) while we drive 16 data lines. Every row picks up data at a slightly different sub-pixel phase because 16 bits / 18 bits = 0.89 pixels per PCLK from the panel's point of view; the fractional offset accumulates across each line and further accumulates from one line to the next, producing the diagonal rather than vertical stripe direction. When every DB pin is driven HIGH at once (WHITE), the 'extra' two bits the PCB leaves floating or tied to a fixed level for 16-line boards suddenly shift the panel's internal interpretation, and what was 'bright stripe on dark background' becomes 'dark stripe on bright background' — the inversion the user photographed. Fix: re-add {0x3A, {0x55}, 1, 0} into kInitCmds[] between the Command2 exit (0xFF with params {0x77,0x01,0x00,0x00,0x00}) and the SLPOUT / DISPON pair. 0x55 on 0x3A programs RGB interface to 16-bit 5-6-5: DB[15..11]=R[4..0], DB[10..5]=G[5..0], DB[4..0]=B[4..0] — which matches initRgbPanel()'s data_gpio_nums[] layout byte-for-byte. Round 19 removed COLMOD on the rationale that espressif's own esp_lcd_st7701 BSP omits it (verified true). But espressif's reference board straps IM[3:0] differently from Waveshare's ESP32-S3-Touch-LCD-2.1 — their panel power-ons into 16-bit mode already; ours power-ons into the datasheet default 0x66 (18-bit). Rounds 17 and 18 also sent 0x3A, but with wrong values or wrong GIP context: round 17 shipped 0x66 (made the 18-bit mismatch explicit instead of fixing it), round 18 shipped 0x55 (right value) but all six BK1 GIP blocks 0xE0..0xED in that table were wrong, so the gate drivers misbehaved and hid the COLMOD fix behind a separate failure. Round 19 threw out both the bad GIP values AND the 0x55 COLMOD. Round 22 combines round 19's verbatim-espressif GIP with round 18's 0x55 COLMOD — the combination we have never actually shipped. Single-line change in src/display/st7701_panel.cpp: new 0x3A entry inserted right before SLPOUT. A long-form comment block above the entry records the round-22 narrative so the next time someone cross-references espressif's BSP and decides COLMOD is redundant, they'll see why it matters for this specific Waveshare panel module. Nothing else changes — round 21's colour-bar diagnostic stays in src/Ui.cpp so we can immediately see whether round 22 produced the expected 'full-screen solid red, then solid green, then solid blue, then solid white' sequence. If that's what the next photos show: COLMOD was it, round 23 removes the colour-bar diagnostic and verifies LVGL renders the Overview page cleanly. If the diagonal stripes survive 0x55: the next suspect is the ESP-IDF 4.4.7 RGB peripheral's interaction with the ST7701's clock/sample-edge conventions — round 23 would try pclk_active_neg back to 1 (we flipped it 1->0 in round 16 but only ever tested via LVGL, where the centred-content masking hid the diagonal pattern), and failing that, step data_width from 16 down to 8 to see whether the peripheral is mis-routing the high byte. Historical context preserved from round 21: insert a boot-time colour-bar diagnostic to disambiguate three distinct hypotheses for the round-17..20 persistent stripe pattern. Round 20 shipped an RGB-bus-timing overhaul (PCLK 14→10 MHz, hsync pulse 8→10, hsync back porch 10→20, hsync front porch 50→20, vsync pulse 2→10, vsync back porch 18→10, vsync front porch 8→10) and the photo came back visually identical to rounds 18/19 — uniform dark blue/purple field with a column of bright blue/cyan vertical stripes compressed into the middle ~1/3 of the round panel. That's now three radically different init sequences (rounds 13–16 stitched, round 17/18 + COLMOD, round 19+ verbatim espressif port) and two very different RGB timing configurations (rounds 14–19 FatihErtugral-style, round 20 Espressif-typical) all producing the SAME visual symptom. The invariance across such wide software changes is the key data point: whatever is wrong is downstream of both the init protocol and the RGB timing — either in geometry (the panel is only receiving data for a subset of its horizontal pixels) or in bit-lane mapping (black rendering as blue and white rendering as cyan/blue due to miswired RGB data pins). A re-read of src/Ui.cpp on the way to round 21 surfaced a plausible third explanation: every widget on the Overview page (the default page that loads at boot) aligns to LV_ALIGN_TOP_MID / LV_ALIGN_CENTER / LV_ALIGN_BOTTOM_MID — the 280x280 wind compass at TOP_MID, the 48pt SOG label at BOTTOM_MID -80, the AWS value at CENTER, the HDG/COG line at BOTTOM_MID -15. All visible LVGL-drawn pixels sit in a narrow vertical column in the middle of the 480-wide screen. If the RGB bit lanes are miswired such that black (0x0000) happens to render as a dark blue/purple and white (0xFFFF) happens to render as bright cyan/blue, the photos from rounds 15–20 are exactly what you'd see: dark-blue field everywhere LVGL drew the screen background, bright-blue stripes everywhere LVGL drew the '--' placeholder text, perfectly centred. That's now plausible enough to be worth testing directly. Round 21 inserts a solid-colour test sequence into src/Ui.cpp::ui::begin() immediately after the successful g_panel.begin() call and BEFORE lv_init(), so it runs against a clean RGB bus with no LVGL involvement. The sequence is g_panel.fillColor(0xF800) → delay(2000) → 0x07E0 → 0x001F → 0xFFFF → 0x0000, giving 2 s of RED, GREEN, BLUE, WHITE then 1 s of BLACK before LVGL takes over. Each fillColor writes a full PSRAM row of the raw uint16_t then repeats it PANEL_HEIGHT times via esp_lcd_panel_draw_bitmap, bypassing LVGL entirely. The photo from each phase maps cleanly onto a failure mode: (a) if each phase fills the ENTIRE round panel with the named solid colour → RGB bus and panel geometry are both healthy, the 'middle stripe band' we've been photographing was just LVGL's centred UI, and round 22 focuses purely on colour mapping (which colour comes out as what); (b) if each phase shows only a narrow middle band of the named colour with the rest in power-on state → geometry is actually broken, the panel is accepting data for only a subset of horizontal pixels per line, and round 22 attacks horizontal addressing (partial-display mode bit in 0xC0 byte 2 SCN, interface-mode mismatch between panel strapping and our 16-line drive, or an IDF-level hactive calculation error); (c) if the colour filled does NOT match what appears on screen (RED fill shows BLUE etc.) → RGB data pins are cross-wired, and the specific 'fill colour → visible colour' table from the photos tells us exactly which five-entry R/G/B sub-block in data_gpio_nums[] to shuffle. This is a one-reboot-cycle, no-scope-needed diagnostic that uniquely identifies which of those three distinct hypotheses we're in, and determines round 22's direction. Only change in this round: ~30 lines inserted into src/Ui.cpp between ST7701.begin() and lv_init(). No src/display/ changes, no platformio.ini changes, no init-table or timing changes — round 20's Espressif-typical timings and round-19's verbatim-espressif init are both preserved. Historical context preserved from round 20: pivot from init-sequence edits to RGB-bus timing. Round 19 shipped a verbatim port of espressif's ST7701 init sequence and the display output did not change from round 18 — same uniform-blue background, same column of green+blue stripes compressed into the middle ~1/3 of the screen. The fact that a completely different init sequence produced an identical visual symptom is diagnostic: the problem is not in what commands we send to the panel, it is in HOW we drive the 16 RGB data lines and their sync/porch signals afterward. Round 20 retunes the RGB peripheral in two parts. (a) PCLK drops from 14 MHz to 10 MHz in display_pins.h::RGB_PCLK_HZ. Rounds 14–19 used 14 MHz because that's what FatihErtugral's working config for the sibling Waveshare 2.8\" ST7701 board ships; but on our 2.1\" 480×480 panel 14 MHz is apparently outrunning the source-driver sampling window given our generous front porch. 10 MHz is well inside the ST7701S-datasheet-guaranteed band (~3 MHz to ~20 MHz) and biases for 'works' over 'max refresh'. We can step back up to 12–14 MHz once the image is coherent. (b) Porches move from FatihErtugral's values to Espressif's Waveshare-BSP typical values. Specifically: hsync_pulse_width 8→10, hsync_back_porch 10→20, hsync_front_porch 50→20, vsync_pulse_width 2→10, vsync_back_porch 18→10, vsync_front_porch 8→10 in st7701_panel.cpp::initRgbPanel(). The single largest delta is hsync_front_porch dropping from 50 to 20 — 50 was ~5x the value Espressif uses for comparable 480×480 ST7701 BSPs and is the strongest suspect for why the panel's HSYNC resync arrives too late per line, with pixels at the end of one line bleeding into the start of the next. The new porch+PCLK combo gives total 530×510 clocks per frame @ 10 MHz = 37 Hz refresh (down from 50 Hz); flickery on a bench but harmless for bring-up. Init sequence is untouched from round 19 (verbatim espressif port). Pin order, backlight, and TCA9554 reset sequence all unchanged. If round 20 visibly changes the stripe pattern — width, shape, or position — timing was involved and round 21 can fine-tune from there. If round 20 shows no change at all (same as rounds 18/19), timing is not the issue and the suspect shifts to pin order or LV_COLOR_16_SWAP polarity; round 21 would then reverse data_gpio_nums to test whether the ESP-IDF 4.4.7 RGB peripheral puts bit 0 on the last array slot rather than the first. Historical context preserved from round 19: that round replaced our round-13 init table (stitched from Nicolai-Electronics + generic ST7701S datasheet) with a verbatim port of espressif/esp-iot-solution/esp_lcd_st7701_rgb.c::vendor_specific_init_default[]. Key fixes in that port were (1) BK3 entry via 0xFF {...,0x13} instead of a stray MIPI NORON, (2) entire 0xE0..0xED GIP block replaced with espressif's known-good values, (3) dropped the 0x3A COLMOD addition from rounds 17/18. None of those changes moved the visual symptom, which is what triggered the round-20 pivot. Round 18's photo showed a uniform blue background with a vertical column of green+blue stripes spanning the middle ~1/3 of the screen — a textbook gate-in-panel (GIP) timing mismatch where most columns of the panel's source drivers never get the right gate pulse and stay in their power-on blue state, while a narrow band actually scans the data we send. Rounds 13–18 used an init table stitched together from Nicolai-Electronics/esp32-component-st7701 + the generic ST7701S datasheet sequence; cross-checking that table against espressif's known-good sequence (pulled from the current master of esp-iot-solution's esp_lcd_st7701 driver) surfaced three systemic problems beyond individual byte differences: (1) Our init opened with '0xFF {0x77,0x01,0x00,0x00,0x00}' then sent '0x13' as a standalone command. We intended 0x13 as a Command2 BK3 selector but the wire bits were the MIPI standard NORON (Normal Display On). Espressif opens with '0xFF {0x77,0x01,0x00,0x00,0x13}' — BK3 entered via the 0xFF parameter — then sends '0xEF {0x08}' in BK3. Our 0xEF landed in normal mode where the command has no effect. (2) The entire 0xE0..0xED GIP block differed. GIP values are what tell the gate drivers when to pulse each row; wrong values → rows that never activate → the mid-band stripe. Espressif's values are the known-good ones for the 480x480 Waveshare ST7701 family. Our 0xB0/0xB1 (BK0 positive/negative gamma) and the BK1 power-rail constants (0xB0 VOP 0x5D→0x8D, 0xB1 VCOM 0x2D→0x48, 0xB2 0x07→0x89, 0xB5 0x08→0x49, 0xB8 0x20→0x32) were also wrong, and an 0xEF 6-byte source-timing fine-trim block in BK1 was missing entirely. (3) Rounds 17 and 18 added a 0x3A COLMOD command (0x66 then 0x55) on the theory that pixel-format was wrong; espressif OMITS 0x3A entirely because the panel's power-on default pixel format is correct for its hardware strapping (IM[3:0] pins on the panel module select 16-bit RGB interface mode). Explicitly setting a non-default COLMOD silently misaligns bits on the RGB bus, which is consistent with the stripe pattern persisting across both 0x66 and 0x55 attempts. Round 19 drops the 0x3A addition. Also removed: the stray '{0x13, {}, 0, 0}' NORON send, the '0xB9 {0x10}' line that isn't in the reference. Also in st7701_panel.cpp: kCmdNoron constant deleted (no longer used), kCmdDispon post-delay changed from 50 ms to 0 ms per espressif. Only the init table changed this round — RGB timings, pin order, backlight, and TCA9554 reset sequence all stay exactly as round 18. If round 19 still stripes, the suspect shifts from 'software init' to 'RGB bus / timing' and round 20 should pivot to: (a) reversing data_gpio_nums pin order (some ESP-IDF 4.4.x builds put bit 0 on the LAST data_gpio_nums slot, not the first), (b) widening hsync_back_porch from 10 to 20 and reducing hsync_front_porch from 50 to 20 to match Espressif's typical 480x480 ST7701 timings, (c) dropping PCLK from 14 MHz to 10 MHz to rule out bus-bandwidth issues. Round 17 added the COLMOD command for the first time (rounds 13–16 had omitted it) and the stripe pattern's dominant colour shifted from 'mostly blue' in round 16 to 'more green and blue' in round 17 — evidence the panel IS responding to COLMOD, but 0x66 was the wrong value for our wiring. 0x66 is what espressif/esp-iot-solution's ST7701 driver uses, but espressif's reference board wires 18 data lines; Waveshare's ESP32-S3-Touch-LCD-2.1 only has 16 (B0..B4, G0..G5, R0..R4). When COLMOD=0x66 the ST7701 expects DB[17..12]=R, DB[11..6]=G, DB[5..0]=B; driving only DB[15..0] means the bit positions shift — our pixel's R MSB (bit 15) lands in the panel's R3 slot, R LSB (bit 11) lands in G5, G MSB (bit 10) lands in G4, etc. That cross-channel bit-shift is exactly the pattern that produces repeating-but-mis-coloured vertical stripes instead of coherent pixels. COLMOD=0x55 sets both the RGB (DPI) and MCU (DBI) interfaces to 16-bit 5-6-5 mode, which matches our 16 data lines exactly: DB[15..11]=R[4..0], DB[10..5]=G[5..0], DB[4..0]=B[4..0] — the natural RGB565 layout the ESP32 RGB peripheral puts on the wire with LV_COLOR_DEPTH=16 and LV_COLOR_16_SWAP=1. The ST7701S datasheet section 10.2.19 lists 0x55 as valid; LovyanGFX's config for Waveshare 16-line ST7701 boards uses it too. Single-byte change: in src/display/st7701_panel.cpp::kInitCmds[], {0x3A, {0x66}, 1, 0} becomes {0x3A, {0x55}, 1, 0}. The long-form comment above the entry now explains the 18bpp-vs-16bpp mismatch in full so the next developer doesn't flip it back to 0x66 chasing the espressif reference. Round 17 context preserved: that round also corrected 0xC0 display-line setting from 0x63 (800 lines) to 0x3B (480 lines) using the (NL+1)*8 formula — that fix stays in place since the 800-line mis-programming was independently wrong. If round 18 still shows stripes, remaining suspects in decreasing likelihood are: (a) horizontal timing — hsync_front_porch of 50 is unusually large vs Espressif's typical 20, widening the back porch at the expense of front porch could align the panel's sampling window (try hsync_pulse_width 10 / hsync_back_porch 20 / hsync_front_porch 20); (b) data_gpio_nums pin order — the ESP32 RGB peripheral might put bit 0 on DB[15] instead of DB[0] on some IDF versions, test by reversing the array; (c) COLMOD=0x50 as an alternative 16bpp value that some ST7701 revisions prefer over 0x55. Round 16 flipped PCLK polarity on the theory that round 15's stripes came from sampling data on the wrong clock edge; that hypothesis did not pan out (post-round-16 flash showed the same stripes, mostly blue hue). Re-reading our init table against espressif/esp-iot-solution's esp_lcd_st7701 driver and a handful of community ST7701 + Waveshare references surfaced two actual problems we had carried since round 13. (1) The init sequence never sends 0x3A. On power-up the ST7701 sits in whatever default pixel-format state its ROM leaves it in, which for RGB-interface operation is ambiguous across ST7701 revisions — some boot into a layout that pulls bits from our 16 data wires in a way that doesn't match RGB565. The mis-alignment between wire-level bits and the panel's internal pipeline bits is a textbook cause of the 'same data repeats as a vertical stripe with a dominant blue channel' pattern the monitor showed: when an RGB565 word (R5 G6 B5 = 16 bits) is read into an 18-bit RGB666 path without the panel being told it's in 18bpp mode, the B channel's LSBs land where G's MSBs would go, R's MSBs get truncated, and what survives is mostly the (large) low-bit blue values. Round 17 inserts {0x3A, {0x66}, 1, 0} — 18-bit RGB666 in RGB-interface mode — right after the 0xFF that exits Command2 vendor mode and before SLPOUT+DISPON. 0x66 is the value the espressif esp-iot-solution ST7701 driver uses, as does Waveshare's own vendor config; the alternative 0x55 (16bpp RGB565) is documented in the ST7701S datasheet but several revisions ship with it unsupported in RGB-interface mode, so 0x66 is the safer match. (2) 0xC0 Display Line Setting: byte 1 encodes (NL+1)*8 = number of display lines. 0x63 = 99, which programs the panel for (99+1)*8 = 800 lines. 480 lines requires NL = 59 = 0x3B, which is what round 17 sets. Driving a 480-line panel while it's internally gated for 800 lines smears rows across the physical array, which is also consistent with the 'middle 50% of the screen' framing in the stripe symptom. Both changes are in src/display/st7701_panel.cpp::kInitCmds[]: new 0x3A entry inserted, existing 0xC0 parameter changed from 0x63 to 0x3B. Long-form comments above both entries record the round-17 narrative so a future reader (likely us in round 20-something) doesn't undo the fix. Touch-controller side effect preserved from round 16: CST820 at 0x15 still ACKed-then-stopped after round 15's safe-state TCA9554 writes held TP_RST (bit 1) asserted low; not a v1 blocker because there's no touch code yet, but round 18+ will need to raise that bit before talking to the CST820. Historical context preserved from round 15: dark-screen fix moved backlight from TCA9554 to raw GPIO6 PWM (ledcSetup+ledcAttachPin+ledcWrite, 20 kHz, 10-bit, full duty) and shifted all TCA9554 bit-mask constants down by one (bit 0 = LCD_RST, bit 1 = TP_RST, bit 2 = LCD_CS, bit 7 = BUZZER) after realising the LGFX #630 EXIO1..EXIO8 labels are 1-indexed helper names mapping to P0..P7. Round 14 history preserved: removed cfg.bounce_buffer_size_px = 0 (that field was added in IDF 5.x; Arduino-ESP32 2.0.16 bundles IDF 4.4.7). Round 16 history preserved: pclk_active_neg 1→0 and vsync_pulse_width 8→2, vsync_front_porch 20→8 to align with FatihErtugral's ESP-IDF driver for the sibling Waveshare 2.8 inch ST7701 board. If round 17 still shows stripes, remaining suspects in decreasing likelihood are (a) RGB data-pin order reversed on one of R/G/B channels (LGFX #630 lists R0..R4, G0..G5, B0..B4 in ascending-bit order but some community repos use descending; swapping both channels' order independently is a cheap test), (b) horizontal timing porch values too tight for this panel sub-variant (try widening hsync_back_porch from 10 to 20 and hsync_front_porch from 50 to 30 to match espressif's defaults), (c) ST7701 init sequence has a gamma or GIP value that doesn't match this cell's glass (B0/B1/E5/E8 blocks)."

set -euo pipefail

# ---- parse args -------------------------------------------------------------
SKIP_BUILD=0
if [[ "${1:-}" == "-n" || "${1:-}" == "--no-build" ]]; then
    SKIP_BUILD=1
    shift
fi
MSG="${1:-${DEFAULT_MSG}}"

# ---- move to repo root ------------------------------------------------------
REPO_ROOT="$(cd "$(dirname "$0")/.." && pwd)"
cd "${REPO_ROOT}"

# ---- sanity check: are we actually in a git repo? ---------------------------
if ! git rev-parse --is-inside-work-tree >/dev/null 2>&1; then
    echo "ERROR: ${REPO_ROOT} is not a git working tree." >&2
    exit 2
fi
BRANCH="$(git rev-parse --abbrev-ref HEAD)"
echo "==> Repo:    ${REPO_ROOT}"
echo "==> Branch:  ${BRANCH}"
echo "==> Message: ${MSG}"

# ---- 1. rebuild firmware (unless --no-build) --------------------------------
# Default env for the packaged binaries is SIM: compiles LVGL + LovyanGFX in
# full, feeds the UI fake NMEA values, and is the one we iterate on day-to-day.
# Override to "safe" for the LVGL-less diagnostic image, or "waveshare_..." for
# production (the prod env still needs an S3-capable NMEA2000 CAN backend
# before it will link — see platformio.ini).
BUILD_ENV="${BUILD_ENV:-sim}"
if [[ "${SKIP_BUILD}" -eq 0 ]]; then
    echo
    echo "==> Rebuilding ${BUILD_ENV} firmware (use -n to skip, or BUILD_ENV=sim ./scripts/update.sh to override)"
    ./scripts/package.sh "${BUILD_ENV}"
else
    echo
    echo "==> Skipping firmware rebuild (--no-build)"
fi

# ---- 2. prepend a dated entry to CHANGELOG.md -------------------------------
# CHANGELOG.md is a human-readable revision list, newest first. Each run of
# this script prepends exactly one entry so the file stays in lock-step with
# actual commits (as opposed to being hand-maintained, which drifts).
CHANGELOG="CHANGELOG.md"
SENTINEL="<!-- entries below, newest first -->"
DATE_STR="$(date +%Y-%m-%d)"
ENTRY="- **${DATE_STR}** — ${MSG}"

if [[ ! -f "${CHANGELOG}" ]]; then
    cat > "${CHANGELOG}" <<EOF
# Changelog

Running revision log for esp32-boat. Maintained automatically by
\`scripts/update.sh\` — each run prepends a dated entry here before committing,
so this file always matches the sequence of commits on the current branch.

${SENTINEL}
${ENTRY}
EOF
    echo
    echo "==> Created ${CHANGELOG} with first entry."
else
    TMP="$(mktemp)"
    awk -v sentinel="${SENTINEL}" -v entry="${ENTRY}" '
        BEGIN { done = 0 }
        { print }
        $0 == sentinel && !done { print entry; done = 1 }
    ' "${CHANGELOG}" > "${TMP}"
    mv "${TMP}" "${CHANGELOG}"
    echo
    echo "==> Prepended entry to ${CHANGELOG}:"
    echo "    ${ENTRY}"
fi

# ---- 3. show the damage -----------------------------------------------------
echo
echo "==> Working-tree changes:"
git status --short
echo
echo "==> Diff summary:"
git diff --stat HEAD || true

# bail cleanly if there's nothing to commit
if [[ -z "$(git status --porcelain)" ]]; then
    echo
    echo "==> Nothing to commit. Working tree clean. Done."
    exit 0
fi

# ---- 4. stage everything under tracked project paths ------------------------
# We explicitly list paths rather than `git add -A` so a stray file in the
# repo root (e.g. a scratch .env, a build log) doesn't sneak into the commit.
echo
echo "==> Staging changes"
git add -- \
    src/ include/ \
    scripts/ \
    binaries/ \
    hardware/ \
    docs/ \
    .github/ \
    README.md LICENSE .gitignore platformio.ini \
    CHANGELOG.md \
    2>/dev/null || true

# Tell the user what actually got staged.
echo
echo "==> Staged for commit:"
git diff --cached --stat

# If nothing is staged (everything in the diff was in a path we don't auto-add),
# stop and let the user run `git add` manually.
if [[ -z "$(git diff --cached --name-only)" ]]; then
    echo
    echo "WARNING: no files were auto-staged. Changes exist but are outside"
    echo "         the paths update.sh manages. Run 'git add <file>' yourself"
    echo "         and re-run this script, or commit manually."
    exit 2
fi

# ---- 5. commit --------------------------------------------------------------
echo
echo "==> Committing: ${MSG}"
git commit -m "${MSG}"

# ---- 6. push ----------------------------------------------------------------
echo
echo "==> Pushing to origin/${BRANCH}"
# -u sets upstream on first push; harmless on subsequent pushes.
if ! git push -u origin "${BRANCH}"; then
    echo
    echo "ERROR: push failed. Commit is local on ${BRANCH} — fix the remote" >&2
    echo "       issue and run 'git push origin ${BRANCH}' when ready." >&2
    exit 2
fi

echo
echo "==> Done. https://github.com/trek2710/esp32-boat/commits/${BRANCH}"
echo "    See CHANGELOG.md for the running revision list."
